def parse_duration(text):
    text = text.replace(' ', '')
    if 'h' in text:
        hours = int(text[:text.index('h')])
    else:
        hours = 0
    if 'm' in text:
        minutes = int(text[text.index('h')+1:]) if 'h' in text else int(text[:text.index('m')])
    else:
        minutes = 0
    return hours * 60 + minutes

def parse_duration(text):
    text = text.replace(' ', '')
    hours = text.split('h')[0] if 'h' in text else '0'
    minutes = text.split('h')[-1].split('m')[0] if 'h' in text else text.split('m')[0]
    return int(hours) * 60 + int(minutes)

def parse_duration(text):
    pattern = r'(\d+)([h|m]?)'
    matches = re.findall(pattern, text)
    total_minutes = 0
    for match in matches:
        value, unit = match
        if unit == 'h':
            total_minutes += int(value) * 60
        elif unit == 'm':
            total_minutes += int(value)
    return total_minutes

